sql:
SELECT class_name
FROM classes
WHERE enrollment > 20;

SELECT admin_name
FROM school_administrators
WHERE julianday('now') - julianday(hire_date) > 5 * 365;

SELECT COUNT(admin_id) AS num_administrators
FROM school_administrators
WHERE years_of_experience > 5;

SELECT category_name, description
FROM school_categories
ORDER BY category_name ASC;

SELECT AVG(total_enrollment) AS average_enrollment
FROM schools
WHERE school_category = 'Public School' AND total_enrollment > 200;

SELECT total_enrollment AS total_students_enrolled
FROM schools
WHERE school_id = 0;
